use strict;
use warnings;
use URI;
use URI::Escape;

sub is_valid_redirect {
    my ($redirect_url) = @_;
    return 0 unless $redirect_url;
    
    my $uri = URI->new($redirect_url);
    return 0 unless $uri->scheme && $uri->host;
    
    my $allowed_hosts = {
        'example.com' => 1,
        'www.example.com' => 1,
    };
    
    my $host = $uri->host;
    return 1 if $allowed_hosts->{$host};
    
    return 0;
}

my $next = $ENV{'QUERY_STRING'} =~ /next=([^&]*)/ ? $1 : '';
my $redirect_url = uri_unescape($next) || '';

if ($redirect_url && is_valid_redirect($redirect_url)) {
    print "Location: $redirect_url\n\n";
